import type { JSX } from 'react';
import type { SeriesActionsTemplate } from '../../../types/series-actions-template.js';
import { VariantShape } from '../../shape/type.js';
/**
 * Shape of a single data series entry rendered inside the tooltip.
 * @public
 */
export type Series = {
    /** Display name of the series. Pass an array for multi-line names. */
    name: string | string[];
    /** The formatted value to display (string, number, or Date). */
    value: string | number | Date;
    /** The color used for the series symbol. */
    color: string;
    /** Optional unit label appended after the main value. */
    valueUnit?: string;
    /** Optional relative value (e.g. percentage) shown alongside the main value. */
    relativeValue?: string | number;
    /** Optional unit label appended after the relative value. */
    relativeValueUnit?: string;
};
/**
 * Truncation options that enable multi-line wrapping for series names.
 * @public
 */
export type TruncationModeMultiLine = {
    /** When `true`, the series name wraps across multiple lines instead of being truncated. */
    multiLine?: true;
};
/**
 * Truncation options that cap series name display to a fixed number of lines.
 * @public
 */
export type TruncationModeMaxLines = {
    /** When `false` or omitted, multi-line wrapping is disabled. */
    multiLine?: false;
    /** Maximum number of lines before the name is truncated. Defaults to `1`. */
    maxLines?: number;
};
/**
 * Union of supported truncation strategies for series name display.
 * @public
 */
export type TooltipTruncationOptions = TruncationModeMultiLine | TruncationModeMaxLines;
/**
 * Visual size variant for the series icon.
 * - `'default'` — standard size.
 * - `'large'` — enlarged icon for emphasis.
 * @public
 */
export type IconStyle = 'default' | 'large';
/**
 * Base props shared across all `OverlayTooltip.SeriesItem` variants.
 * @public
 */
export type BaseSeriesItemProps = {
    /** Display name of the series. Pass an array to enable multi-line rendering. */
    name: Series['name'];
    /** Optional descriptive text shown next to the series name. */
    description?: string;
    /** The formatted value to display. */
    value: Series['value'];
    /** Optional unit label appended after the main value. */
    valueUnit?: string;
    /** Optional relative value (e.g. a percentage) shown next to the main value. */
    relativeValue?: Series['relativeValue'];
    /** Optional unit label appended after the relative value. */
    relativeValueUnit?: string;
    /** Enables multi-line wrapping for the series name. */
    multiLine?: boolean;
    /** Maximum number of lines to display before truncating the series name. */
    maxLines?: number;
    /** Controls the visual size of the series icon. */
    iconStyle?: IconStyle;
} & TooltipTruncationOptions;
/**
 * Optional actions rendered inside a series item row.
 * @public
 */
export type SeriesItemActions = {
    /** Factory function returning the actions to render for this series entry. */
    actions?: () => SeriesActionsTemplate;
};
/**
 * Props for a series item rendered with a colored geometric shape symbol.
 * @public
 */
export type ShapeSeriesItemProps = BaseSeriesItemProps & SeriesItemActions & {
    /** Fill color for the shape symbol. */
    color: string;
    /** Shape variant to use. Defaults to a filled circle. */
    shape?: VariantShape;
    symbol?: never;
    icon?: never;
};
/**
 * Props for a series item rendered with a custom SVG path symbol string.
 * @public
 */
export type SymbolSeriesItemProps = BaseSeriesItemProps & SeriesItemActions & {
    /** SVG path string used as the series symbol. */
    symbol: string;
    color?: never;
    shape?: never;
    icon?: never;
};
/**
 * Props for a series item rendered with a custom JSX icon element.
 * @public
 */
export type IconSeriesItemProps = BaseSeriesItemProps & SeriesItemActions & {
    /** JSX element used as the series icon. */
    icon: JSX.Element;
    color?: never;
    shape?: never;
    symbol?: never;
};
/**
 * Public union — enforces mutual exclusivity at the call site via `never`.
 * Consumers must pass exactly one of: color, symbol, or icon.
 * @public
 */
export type SeriesItemProps = ShapeSeriesItemProps | SymbolSeriesItemProps | IconSeriesItemProps;
export type InternalSeriesItemProps = Omit<BaseSeriesItemProps, 'multiLine' | 'maxLines '> & {
    color?: string;
    shape?: VariantShape;
    symbol?: string;
    icon?: JSX.Element;
    actions?: () => SeriesActionsTemplate;
    multiLine?: boolean;
    maxLines?: number;
};
